3938	\begin{lemma}[Transport of a presentation along a colimit-preserving functor]
3939	  \label{lem:presentation_map_mathlib}
3940	  \lean{SheafOfModules.Presentation.map}
3941	  \mathlibok
3942	  \textit{Provided by Mathlib.}
3943	  Let \(F : \operatorname{SheafOfModules} R \to \operatorname{SheafOfModules} S\) be a functor between
3944	  categories of sheaves of modules (possibly over different sites) that preserves colimits and carries
3945	  the unit object to the unit object, \(F(\mathcal{O}_R) \cong \mathcal{O}_S\). Then any presentation
3946	  of a sheaf of modules \(\mathcal{M}\) — a right-exact sequence
3947	  \(\mathcal{O}_R^{(J)} \to \mathcal{O}_R^{(I)} \to \mathcal{M} \to 0\) of generators and relations —
3948	  is carried by \(F\) to a presentation of \(F(\mathcal{M})\).
3949	\end{lemma}
3950	
3951	\begin{lemma}[Transport of a presentation across an isomorphism]
3952	  \label{lem:presentation_ofIsIso_mathlib}
3953	  \lean{SheafOfModules.Presentation.ofIsIso}
3954	  \mathlibok
3955	  \textit{Provided by Mathlib.}
3956	  Let \(\phi : \mathcal{M} \to \mathcal{N}\) be an isomorphism of sheaves of modules. A presentation of
3957	  \(\mathcal{M}\) induces a presentation of \(\mathcal{N}\), by composing its generators and relations
3958	  with \(\phi\).
3959	\end{lemma}
3960	
3961	\begin{lemma}[Site-equivalence transport of sheaves of modules]
3962	  \label{lem:pushforwardPushforwardEquivalence_mathlib}
3963	  \lean{SheafOfModules.pushforwardPushforwardEquivalence}
3964	  \mathlibok
3965	  \textit{Provided by Mathlib.}
3966	  Let \(e : \mathcal{C} \simeq \mathcal{D}\) be an equivalence of sites and let
3967	  \(\mathcal{O}_{\mathcal{C}}\), \(\mathcal{O}_{\mathcal{D}}\) be sheaves of rings related by
3968	  compatible comparison maps along \(e\). Then \(e\) induces an equivalence of categories of sheaves of
3969	  modules \(\operatorname{SheafOfModules} \mathcal{O}_{\mathcal{C}} \simeq
3970	  \operatorname{SheafOfModules} \mathcal{O}_{\mathcal{D}}\), compatible with the underlying
3971	  pushforwards. This is the engine that bridges two pictures of ``restriction to an open''.
3972	\end{lemma}
3973	
3974	\begin{lemma}[The over-site of a topological space is equivalent to its subspace site]

9560	  Let \(\mathcal{F}\) be a sheaf of modules and \((U_i)_{i \in I}\) a family of objects of the site
9561	  covering the terminal object. If each over-picture restriction \(\mathcal{F}.\operatorname{over} U_i\)
9562	  is quasi-coherent, then \(\mathcal{F}\) is quasi-coherent.
9563	\end{lemma}
9564	
9565	\begin{lemma}[Extraction of the local quasi-coherence datum]
9566	  \label{lem:nonempty_quasicoherentData_mathlib}
9567	  \lean{SheafOfModules.IsQuasicoherent.nonempty_quasicoherentData}
9568	  \mathlibok
9569	  \textit{Provided by Mathlib.}
9570	  A quasi-coherent sheaf of modules \(\mathcal{F}\) admits a quasi-coherence datum: there is a family
9571	  \((U_i)_{i \in I}\) of objects of the site covering the terminal object together with, for each \(i\),
9572	  a presentation of \(\mathcal{F}.\operatorname{over} U_i\).
9573	\end{lemma}
