8280	\begin{lemma}
8281	[Local vanishing of the evaluated augmented {\v C}ech homology]
8282	  \label{lem:cechSection_isZero_homology}
8283	  \lean{AlgebraicGeometry.cechSection_isZero_homology}
8284	  \uses{lem:cechSection_complex_iso, lem:cechSection_contractible,
8285	    lem:isZero_homology_of_homotopy_id_zero}
8286	  Let \(V \le \operatorname{coverOpen}\mathcal{U}\,i\) for some index \(i\). Then for every
8287	  degree \(p\) the homology \(H^p(D^\bullet)\) of the augmented {\v C}ech complex evaluated at
8288	  \(V\) (the complex \(D^\bullet\) of Lemma~\ref{lem:cechSection_complex_iso}) is a zero
8289	  object; equivalently \(D^\bullet\) carries a contracting homotopy \(\mathrm{id}_{D^\bullet}
8290	  \simeq 0\). This is the residual obligation of Step~3 of
8291	  Lemma~\ref{lem:cech_augmented_resolution}.
8292	\end{lemma}
8293	\begin{proof}
8294	  \uses{lem:cechSection_complex_iso, lem:cechSection_contractible,
8295	    lem:isZero_homology_of_homotopy_id_zero}
8296	  By Lemma~\ref{lem:cechSection_complex_iso} the evaluated complex \(D^\bullet\) is
8297	  isomorphic to the augmented concrete section {\v C}ech complex \(D'^\bullet_{\mathrm{aug}}\).
8298	  The hypothesis \(V \le \operatorname{coverOpen}\mathcal{U}\,i\) places \(V\) inside one cover
8299	  member, so Lemma~\ref{lem:cechSection_contractible} gives a contracting homotopy
8300	  \(\mathrm{id}_{D'^\bullet_{\mathrm{aug}}} \simeq 0\); transporting it across the complex
8301	  isomorphism yields \(\mathrm{id}_{D^\bullet} \simeq 0\).
8302	  Lemma~\ref{lem:isZero_homology_of_homotopy_id_zero} then makes
8303	  \(H^p(D^\bullet)\) a zero object in every degree.
8304	\end{proof}
