8308	\begin{lemma}[Pushforward sections are sections over the preimage]
8309	  \label{lem:pushforward_obj_obj_mathlib}
8310	  \lean{AlgebraicGeometry.Scheme.Modules.pushforward_obj_obj}
8311	  \mathlibok
8312	  \textit{Provided by Mathlib.}
8313	  For a morphism \(f : X \to Y\), an \(\mathcal{O}_X\)-module \(\mathcal{M}\), and an open
8314	  \(U \subseteq Y\), the sections of the pushforward \(f_*\mathcal{M}\) over \(U\) coincide
8315	  definitionally with the sections of \(\mathcal{M}\) over the preimage:
8316	  \(\Gamma(U, f_*\mathcal{M}) = \Gamma(f^{-1}(U), \mathcal{M})\).
8317	\end{lemma}
